PREFIX ns: <http://rdf.freebase.com/ns/>
SELECT DISTINCT ?yearWon ?lastSuperBowl ?coach1996
WHERE {
  # Years Dallas Cowboys won the Super Bowl
  ns:m.02896 ns:sports.sports_team.championships ?winEvent .
  FILTER(?winEvent = ns:m.06x5s)
  ?winEvent ns:time.event.start_date ?startDate .
  BIND(year(xsd:dateTime(?startDate)) AS ?yearWon)

  # Last time Dallas Cowboys went to the Super Bowl
  {
    ns:m.06x5s ns:sports.sports_championship.events ?sbEvent .
    {
      ?sbEvent ns:sports.sports_championship_event.runner_up ns:m.02896 .
    }
    UNION
    {
      ?sbEvent ns:sports.sports_championship_event.champion ns:m.02896 .
    }
    ?sbEvent ns:time.event.start_date ?startDateSB .
  }
  ORDER BY DESC(?startDateSB)
  LIMIT 1
  BIND(year(xsd:dateTime(?startDateSB)) AS ?lastSuperBowl)

  # Coach of Dallas Cowboys in 1996
  ns:m.02896 ns:american_football.football_team.historical_coaching_staff ?coachPos .
  ?coachPos ns:american_football.football_historical_coach_position.coach ?coach1996 .
