      (?fromDate <= "1996-12-31T23:59:59Z"^^xsd:dateTime)
    )
  )
  FILTER(
    (
      NOT EXISTS {?coachPos ns:american_football.football_historical_coach_position.to ?toDate} || 
      (?toDate >= "1996-01-01T00:00:00Z"^^xsd:dateTime)
    )
  )
}

